## Set up Stripe Subscriptions with Billing Portal

### Prerequisites
- Stripe account with test mode enabled
- Next.js app with App Router
- Authentication (Clerk or Auth.js) for user identity

### Step 1: Install Stripe SDK

```bash
npm install stripe @stripe/stripe-js
```

### Step 2: Set environment variables

Add to `.env.local`:
```env
STRIPE_SECRET_KEY=sk_test_...
STRIPE_WEBHOOK_SECRET=whsec_...
NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY=pk_test_...
STRIPE_PRICE_STARTER=price_...
STRIPE_PRICE_PRO=price_...
NEXT_PUBLIC_APP_URL=http://localhost:3000
```

### Step 3: Create Stripe utility

```typescript
// lib/stripe.ts
import Stripe from 'stripe';

export const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
  apiVersion: '2025-04-30.basil',
});
```

### Step 4: Create Price IDs in Stripe Dashboard

1. Go to Stripe Dashboard → Products → Add product
2. Set recurring pricing (monthly or annual billing interval)
3. Copy each Price ID (`price_xxx`) into your `.env.local`

```typescript
// lib/stripe-config.ts
export const PLANS = {
  starter: {
    priceId: process.env.STRIPE_PRICE_STARTER!,
    name: 'Starter',
    price: 9,
    features: ['5 projects', '10GB storage'],
  },
  pro: {
    priceId: process.env.STRIPE_PRICE_PRO!,
    name: 'Pro',
    price: 29,
    features: ['Unlimited projects', '100GB storage'],
  },
} as const;
```

### Step 5: Create Checkout Session API route

```typescript
// app/api/stripe/checkout/route.ts
import { NextRequest, NextResponse } from 'next/server';
import { stripe } from '@/lib/stripe';

export async function POST(req: NextRequest) {
  const { priceId, userId, email, customerId } = await req.json();

  const session = await stripe.checkout.sessions.create({
    mode: 'subscription',
    payment_method_types: ['card'],
    // Reuse existing customer if available, else create by email
    ...(customerId ? { customer: customerId } : { customer_email: email }),
    line_items: [{ price: priceId, quantity: 1 }],
    success_url: `${process.env.NEXT_PUBLIC_APP_URL}/dashboard?success=true`,
    cancel_url: `${process.env.NEXT_PUBLIC_APP_URL}/pricing`,
    metadata: { userId },
  });

  return NextResponse.json({ url: session.url });
}
```

### Step 6: Create Billing Portal API route

```typescript
// app/api/stripe/portal/route.ts
import { NextRequest, NextResponse } from 'next/server';
import { stripe } from '@/lib/stripe';

export async function POST(req: NextRequest) {
  const { customerId } = await req.json();

  const session = await stripe.billingPortal.sessions.create({
    customer: customerId,
    return_url: `${process.env.NEXT_PUBLIC_APP_URL}/dashboard/billing`,
  });

  return NextResponse.json({ url: session.url });
}
```

Then go to **Stripe Dashboard → Settings → Customer portal → Activate** to enable the portal.

### Step 7: Webhook handler for subscription lifecycle

```typescript
// app/api/stripe/webhook/route.ts
import { NextRequest, NextResponse } from 'next/server';
import { stripe } from '@/lib/stripe';
import Stripe from 'stripe';

export async function POST(req: NextRequest) {
  const body = await req.text(); // MUST use req.text() — never req.json()
  const sig = req.headers.get('stripe-signature')!;

  let event: Stripe.Event;
  try {
    event = stripe.webhooks.constructEvent(
      body,
      sig,
      process.env.STRIPE_WEBHOOK_SECRET!
    );
  } catch {
    return NextResponse.json({ error: 'Invalid signature' }, { status: 400 });
  }

  switch (event.type) {
    case 'checkout.session.completed': {
      const session = event.data.object as Stripe.CheckoutSession;
      await handleSubscriptionCreated(
        session.metadata!.userId,
        session.customer as string,
        session.subscription as string
      );
      break;
    }
    case 'customer.subscription.updated': {
      const sub = event.data.object as Stripe.Subscription;
      await handleSubscriptionUpdated(sub);
      break;
    }
    case 'customer.subscription.deleted': {
      const sub = event.data.object as Stripe.Subscription;
      await handleSubscriptionDeleted(sub);
      break;
    }
    case 'invoice.payment_failed': {
      // Notify user — consider sending an email via Resend
      break;
    }
  }

  return NextResponse.json({ received: true });
}

async function handleSubscriptionCreated(
  userId: string,
  customerId: string,
  subscriptionId: string
) {
  const subscription = await stripe.subscriptions.retrieve(subscriptionId);
  // Persist to DB: customerId, subscriptionId, status, priceId, currentPeriodEnd
  console.log('Subscription created', { userId, customerId, status: subscription.status });
}

async function handleSubscriptionUpdated(sub: Stripe.Subscription) {
  // Update DB: status, currentPeriodEnd, cancelAtPeriodEnd
  console.log('Subscription updated', sub.id, sub.status);
}

async function handleSubscriptionDeleted(sub: Stripe.Subscription) {
  // Remove access: set subscriptionId to null, status to 'canceled'
  console.log('Subscription deleted', sub.id);
}
```

### Step 8: Store subscription data (Prisma schema example)

```prisma
model User {
  id                     String    @id
  email                  String    @unique
  stripeCustomerId       String?   @unique
  stripeSubscriptionId   String?   @unique
  stripePriceId          String?
  stripeCurrentPeriodEnd DateTime?
  stripeStatus           String?   // 'active' | 'canceled' | 'past_due'
}
```

### Step 9: Pricing page component

```typescript
// app/pricing/page.tsx
'use client';
import { PLANS } from '@/lib/stripe-config';

export default function PricingPage() {
  const handleCheckout = async (priceId: string) => {
    const res = await fetch('/api/stripe/checkout', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ priceId, userId: 'replace_with_auth_user_id', email: 'user@example.com' }),
    });
    const { url } = await res.json();
    window.location.href = url;
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-3xl mx-auto p-8">
      {Object.values(PLANS).map((plan) => (
        <div key={plan.priceId} className="border rounded-xl p-6 space-y-4">
          <h2 className="text-2xl font-bold">{plan.name}</h2>
          <p className="text-4xl font-bold">${plan.price}<span className="text-lg font-normal text-gray-500">/mo</span></p>
          <ul className="space-y-1">
            {plan.features.map((f) => <li key={f}>✓ {f}</li>)}
          </ul>
          <button
            onClick={() => handleCheckout(plan.priceId)}
            className="w-full bg-black text-white py-2 rounded-lg"
          >
            Get started
          </button>
        </div>
      ))}
    </div>
  );
}
```

### Step 10: Billing management button

```typescript
// components/ManageBillingButton.tsx
'use client';
export function ManageBillingButton({ customerId }: { customerId: string }) {
  const handlePortal = async () => {
    const res = await fetch('/api/stripe/portal', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ customerId }),
    });
    const { url } = await res.json();
    window.location.href = url;
  };

  return (
    <button onClick={handlePortal} className="border px-4 py-2 rounded">
      Manage billing
    </button>
  );
}
```

### Step 11: Test with Stripe CLI

```bash
# Install Stripe CLI and login
stripe listen --forward-to localhost:3000/api/stripe/webhook

# Trigger a test event
stripe trigger customer.subscription.created

# Use test card: 4242 4242 4242 4242, any future date, any CVC
```

## Common Errors

- **`No such price` error**: Price IDs must be exact. Check for test vs. live mode mismatch — test keys use `price_test_` prefixes on some accounts.
- **Webhook signature verification fails**: You must use `req.text()` before `constructEvent`, never `req.json()`. Any body parsing breaks the raw signature.
- **Billing portal returns 404**: The customer portal must be explicitly activated in Stripe Dashboard → Settings → Customer portal.
- **`customer.subscription.updated` not firing**: Verify all required webhook events are enabled in Stripe Dashboard → Developers → Webhooks → your endpoint.
- **Duplicate Stripe customers**: Always check for an existing `stripeCustomerId` in your DB before creating a new customer; pass `customer:` instead of `customer_email:` at checkout.
- **User retains access after canceling**: You must handle the `customer.subscription.deleted` webhook to revoke access.

## What NOT to do

- Do NOT use `req.json()` or any body parser before calling `stripe.webhooks.constructEvent` — this will always fail signature verification.
- Do NOT create a new Stripe Customer on every checkout session — always check for an existing `stripeCustomerId` first.
- Do NOT skip `customer.subscription.deleted` — this is the only reliable signal that a subscription ended; skipping it grants indefinite access.
- Do NOT store card numbers or payment details yourself — Stripe's hosted checkout handles all PCI compliance.
- Do NOT hardcode Price IDs in client-side code — use environment variables or a server-side config.
- Do NOT use the same webhook secret for test and production — they are different endpoints with different secrets.
